import { readFileSync } from 'fs';
import { execSync } from 'child_process';

const input = JSON.parse(readFileSync(0, 'utf8'));
const engineerName = (process.env.ENGINEER_NAME || '').trim();
const personalized = engineerName && Math.random() < 0.3;
const msg = personalized
  ? `${engineerName}, your agent needs your input`
  : 'Your agent needs your input';

try {
  if (process.platform === 'darwin') {
    execSync(`say "${msg.replace(/"/g, '')}"`, { timeout: 10000, stdio: 'ignore' });
  } else {
    execSync(`espeak "${msg.replace(/"/g, '')}"`, { timeout: 10000, stdio: 'ignore' });
  }
} catch {}

