import { readFileSync, writeFileSync, mkdirSync, existsSync, unlinkSync } from 'fs';
import { join } from 'path';
import { execSync } from 'child_process';

const input = JSON.parse(readFileSync(0, 'utf8'));
const agentName = input.agent_name || '';
const lockDir = join(process.cwd(), '.claude', 'data', 'tts_queue');
const lockFile = join(lockDir, 'tts.lock');
mkdirSync(lockDir, { recursive: true });

const deadline = Date.now() + 30000;
while (existsSync(lockFile) && Date.now() < deadline) {
  try { execSync('sleep 0.1', { stdio: 'ignore', timeout: 200 }); } catch { break; }
}
try { writeFileSync(lockFile, JSON.stringify({ pid: process.pid, ts: new Date().toISOString() })); } catch {}

const messages = ['Subagent complete', 'Agent task done', 'Subagent finished'];
const base = messages[Math.floor(Math.random() * messages.length)];
const msg = agentName ? `${agentName} complete` : base;

try {
  if (process.platform === 'darwin') {
    execSync(`say "${msg.replace(/"/g, '')}"`, { timeout: 10000, stdio: 'ignore' });
  } else {
    execSync(`espeak "${msg.replace(/"/g, '')}"`, { timeout: 10000, stdio: 'ignore' });
  }
} finally {
  try { unlinkSync(lockFile); } catch {}
}

import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'fs';
import { join } from 'path';

const input = JSON.parse(readFileSync(0, 'utf8'));
const sessionId = input.session_id || 'unknown';
const sessionsDir = join(process.cwd(), '.claude', 'data', 'sessions');
mkdirSync(sessionsDir, { recursive: true });
const sessionFile = join(sessionsDir, `${sessionId}.json`);

let sessionData = { session_id: sessionId, prompts: [] };
