import { readFileSync, copyFileSync, mkdirSync, existsSync } from 'fs';
import { join, basename } from 'path';

const input = JSON.parse(readFileSync(0, 'utf8'));
const transcriptPath = input.transcript_path || '';
const trigger = input.trigger || 'unknown';

if (transcriptPath && existsSync(transcriptPath)) {
  const backupDir = join(process.cwd(), 'logs', 'transcript_backups');
  mkdirSync(backupDir, { recursive: true });
  const timestamp = new Date().toISOString().replace(/[:.]/g, '').slice(0, 15);
  const stem = basename(transcriptPath).replace(/\.jsonl$/, '');
  const dest = join(backupDir, `${stem}_pre_compact_${trigger}_${timestamp}.jsonl`);
  try { copyFileSync(transcriptPath, dest); } catch {}
}

import { readFileSync } from 'fs';

const input = JSON.parse(readFileSync(0, 'utf8'));
const toolName = input.tool_name || '';
const toolInput = input.tool_input || {};

const SAFE_BASH = [
  /^ls/, /^pwd/, /^echo/, /^cat(?!.*>)/, /^head/, /^tail/, /^wc/,
  /^which/, /^whereis/, /^file/, /^stat/,
  /^git\s+(status|log|diff|show|branch|tag)/,
  /^npm\s+(list|ls|outdated|view)/
];

const readOnlyTools = ['Read', 'Glob', 'Grep'];
let allow = readOnlyTools.includes(toolName);

if (!allow && toolName === 'Bash') {
  const cmd = (toolInput.command || '').trim();
  allow = SAFE_BASH.some(p => p.test(cmd));
}

if (allow) {
  process.stdout.write(JSON.stringify({
    hookSpecificOutput: {
      hookEventName: 'PermissionRequest',
      decision: { behavior: 'allow' }
    }
  }));
}

