import { readFileSync, existsSync } from 'fs';
import { execSync } from 'child_process';

JSON.parse(readFileSync(0, 'utf8'));

function available(cmd) {
  try { execSync(`which ${cmd}`, { stdio: 'ignore', timeout: 3000 }); return true; } catch { return false; }
}

for (const dep of ['node', 'git']) {
  if (!available(dep)) process.stderr.write(`Warning: ${dep} not found in PATH\n`);
}

if (existsSync('package.json') && existsSync('package-lock.json')) {
  try { execSync('npm ci --prefer-offline', { timeout: 60000, stdio: 'ignore' }); } catch {
    try { execSync('npm install', { timeout: 60000, stdio: 'ignore' }); } catch {}
  }
} else if (existsSync('pyproject.toml') || existsSync('uv.lock')) {
  try { execSync('uv sync', { timeout: 60000, stdio: 'ignore' }); } catch {}
}

import { readFileSync, readdirSync, unlinkSync, statSync } from 'fs';
import { join } from 'path';

JSON.parse(readFileSync(0, 'utf8'));
const logDir = join(process.cwd(), 'logs');

try {
  const files = readdirSync(logDir);
  for (const f of files) {
    const fullPath = join(logDir, f);
    if (f.endsWith('.tmp')) {
      try { unlinkSync(fullPath); } catch {}
    }
    if (f === 'chat.json') {
      try {
        const age = Date.now() - statSync(fullPath).mtimeMs;
        if (age > 86400000) unlinkSync(fullPath);
      } catch {}
    }
  }
} catch {}

import { readFileSync } from 'fs';
import { join } from 'path';

const input = JSON.parse(readFileSync(0, 'utf8'));

if (input.source !== 'compact') process.exit(0);

const projectDir = process.env.CLAUDE_PROJECT_DIR || process.cwd();
let context = '';

try {
  const claudeMd = readFileSync(join(projectDir, 'CLAUDE.md'), 'utf8');
  // Extract key conventions section only
  const match = claudeMd.match(/##[\s\S]{0,500}/);
  context = match ? match[0] : claudeMd.substring(0, 500);
} catch {
  context = 'Context compacted — please review CLAUDE.md for project conventions.';
}

process.stdout.write(`[Post-compaction reminder]\n${context}\n`);
process.exit(0);

